{"command": "cat <<'EOF' > lua_interpreter.py
import sys
import os
import re

# Runtime Helpers
class Table:
    def __init__(self, *args, **kwargs):
        self.dict = {}
        self.array = list(args)
        for k, v in kwargs.items():
            self.dict[k] = v

    def __getitem__(self, key):
        if isinstance(key, (int, float)):
            idx = int(key)
            if idx == key and 1 <= idx <= len(self.array):
                return self.array[idx - 1]
        return self.dict.get(key, None)

    def __setitem__(self, key, value):
        if isinstance(key, (int, float)):
            idx = int(key)
            if idx == key:
                if idx == len(self.array) + 1:
                    self.array.append(value)
                    return
                elif 1 <= idx <= len(self.array):
                    self.array[idx - 1] = value
                    return
        self.dict[key] = value

    def __len__(self):
        return len(self.array)

    def __str__(self):
        return f"table: {hex(id(self))}"

def print_lua(*args):
    def lua_str(val):
        if val is None:
            return "nil"
        if isinstance(val, bool):
            return "true" if val else "false"
        if isinstance(val, Table):
            return str(val)
        return str(val)
    sys.stdout.write('\t'.join(lua_str(x) for x in args) + '\n')

def type_lua(val):
    if val is None:
        return "nil"
    if isinstance(val, bool):
        return "boolean"
    if isinstance(val, (int, float)):
        return "number"
    if isinstance(val, str):
        return "string"
    if isinstance(val, Table):
        return "table"
    if callable(val):
        return "function"
    return "userdata"

# Simple Transpiler
def transpile(lua_code):
    # This transpiler translates basic Lua constructs into Python
    lines = lua_code.split('\n')
    py_lines = ["from lua_interpreter import Table, print_lua, type_lua", "import os, sys", ""]
    indent = 0

    for line in lines:
        stripped = line.strip()
        if not stripped:
            py_lines.append("")
            continue

        if stripped.startswith("--"):
            py_lines.append("    " * indent + "# " + stripped[2:])
            continue

        if stripped == "end" or stripped == "}":
            indent = max(0, indent - 1)
            continue

        py_line = "    " * indent

        # Replace keywords
        line_trans = stripped
        line_trans = re.sub(r'\bnil\b', 'None', line_trans)
        line_trans = re.sub(r'\btrue\b', 'True', line_trans)
        line_trans = re.sub(r'\bfalse\b', 'False', line_trans)
        line_trans = re.sub(r'\blocal\s+', '', line_trans)

        # for loop
        m = re.match(r"for\s+(\w+)\s*=\s*(.+)\s*,\s*(.+)\s*do", line_trans)
        if m:
            var, start, stop = m.groups()
            py_line += f"for {var} in range(int({start}), int({stop}) + 1):"
            py_lines.append(py_line)
            indent += 1
            continue

        # function
        m = re.match(r"function\s+(\w+)\s*\((.*)\)", line_trans)
        if m:
            name, args = m.groups()
            py_line += f"def {name}({args}):"
            py_lines.append(py_line)
            indent += 1
            continue

        # print
        if line_trans.startswith("print("):
            line_trans = "print_lua" + line_trans[5:]

        py_line += line_trans
        py_lines.append(py_line)

    return '\n'.join(py_lines)

def run_lua(lua_code, args=None):
    if args is None:
        args = []
    py_code = transpile(lua_code)
    # Expose runtime builtins
    global_env = {
        "Table": Table,
        "print": print_lua,
        "type": type_lua,
        "arg": Table(*args),
        "os": os,
        "sys": sys
    }
    exec(py_code, global_env)

if __name__ == "__main__":
    if len(sys.argv) > 1 and sys.argv[1] == "-e":
        run_lua(sys.argv[2], sys.argv[3:])
